const state = $getWorkflowStaticData('global');
const currentYear = new Date().getFullYear();
const nextTaxYear = currentYear + 1;

const checklist = [
  `1. IRS Revenue Procedure for TY${nextTaxYear} — check if released at <https://www.irs.gov/irb|IRS Internal Revenue Bulletin>`,
  `2. Run tax extraction: \`EXTRACT_TAX_YEAR=${nextTaxYear} pnpm extract:tax\` in \`packages/data\``,
  `3. Run formation update: \`pnpm extract:formation\` (fees change annually)`,
  `4. Run full review: \`pnpm review\` — fix all failures`,
  `5. Run test suite: \`pnpm test\` — all 1700+ tests must pass`,
  `6. Add known-good anchor values for TY${nextTaxYear} in \`tests/sanity.test.ts\``,
  `7. Run \`pnpm review:approve\` to stamp all data as human-reviewed`,
  `8. Create PR and merge to main`,
  `9. Verify CI passes on the PR`,
  `10. Post confirmation to #engineering when done`
];

const taxFoundationUrl = `https://taxfoundation.org/data/all/state/state-income-tax-rates`;

state.lastTriggered = new Date().toISOString();
state.targetTaxYear = nextTaxYear;

return [{ json: { checklist, nextTaxYear, taxFoundationUrl } }];

const { checklist, nextTaxYear, taxFoundationUrl } = $input.first().json;
const botToken = $env.SLACK_BOT_TOKEN || '';
if (!botToken) return [];

const parts = [
  `:calendar: *Annual Tax Data Update — TY${nextTaxYear}*\n`,
  `It's October! Time to extract and validate tax data for the upcoming filing season.\n`,
  '*Checklist:*'
];

for (const item of checklist) {
  parts.push(`\u2022 ${item}`);
}

parts.push(`\n*Key resource*: <${taxFoundationUrl}|Tax Foundation State Income Tax Rates>`);
parts.push(`\n:thread: Reply in this thread with progress updates.`);

const message = parts.join('\n');
return [{ json: { message, channel: 'C0ALLEKR9FZ' } }];
